import{c as t,Q as n,j as s,m as e}from"./chunks/framework.Bhbi9jCp.js";const q=JSON.parse('{"title":"数据组件与 DataFixerUpper:物品新模型与版本迁移","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/17-数据组件与DataFixerUpper-物品新模型与版本迁移.md","filePath":"minecraftLearning/17-数据组件与DataFixerUpper-物品新模型与版本迁移.md","lastUpdated":1781676649000}'),o={name:"minecraftLearning/17-数据组件与DataFixerUpper-物品新模型与版本迁移.md"};function p(r,a,i,l,c,d){return n(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="数据组件与-datafixerupper-物品新模型与版本迁移" tabindex="-1">数据组件与 DataFixerUpper:物品新模型与版本迁移 <a class="header-anchor" href="#数据组件与-datafixerupper-物品新模型与版本迁移" aria-label="Permalink to &quot;数据组件与 DataFixerUpper:物品新模型与版本迁移&quot;">​</a></h1><p>第 08 篇讲 NBT 的时候,我说它是 Minecraft &quot;万物的统一序列化格式&quot;——带类型、可嵌套、紧凑。这话现在仍然对,但物品(ItemStack)这块,在 1.20.5 发生了一次&quot;地基级&quot;的重构:<strong>物品的数据模型从&quot;一坨自由 NBT&quot;换成了&quot;一组强类型组件&quot;</strong>。这一篇讲清楚两件事——新模型长什么样、为什么值得改,以及一个配套但更底层的机制:Minecraft 凭什么让你十年前的存档还能在今天打开,也就是 DataFixerUpper。</p><blockquote><p>一句话先记住:这两件事是同一个方向上的两步——<strong>把数据从&quot;弱类型、随便塞的 NBT&quot;推向&quot;强类型、可校验、可迁移的结构&quot;</strong>。组件解决&quot;物品当下怎么存&quot;,DFU 解决&quot;旧结构怎么变成新结构&quot;。</p></blockquote><hr><h2 id="一、旧世界-物品-种类-一坨-tag" tabindex="-1">一、旧世界:物品 = 种类 + 一坨 <code>tag</code> <a class="header-anchor" href="#一、旧世界-物品-种类-一坨-tag" aria-label="Permalink to &quot;一、旧世界:物品 = 种类 + 一坨 \`tag\`&quot;">​</a></h2><p>1.20.5 之前,一个 ItemStack 在数据上是这样:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  id: &quot;minecraft:diamond_sword&quot;,</span></span>
<span class="line"><span>  Count: 1,</span></span>
<span class="line"><span>  tag: {                         ← 一个自由的 NBT Compound,什么都能往里塞</span></span>
<span class="line"><span>    Damage: 12,</span></span>
<span class="line"><span>    Enchantments: [{id:&quot;minecraft:sharpness&quot;, lvl:5}],</span></span>
<span class="line"><span>    display: { Name: &#39;{&quot;text&quot;:&quot;断钢&quot;}&#39;, Lore: [...] },</span></span>
<span class="line"><span>    AttributeModifiers: [...],</span></span>
<span class="line"><span>    CustomModelData: 1234,</span></span>
<span class="line"><span>    ...</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>核心问题全在那个 <code>tag</code> 上:<strong>它是一个没有 schema 的口袋</strong>。</p><ul><li><strong>弱类型</strong>:<code>tag</code> 里允许出现任何键、任何嵌套。一个键拼错(<code>Enchantment</code> 漏个 s),不会报错,只是静默失效。</li><li><strong>难校验</strong>:游戏没法在&quot;物品被创建&quot;这一刻就确认它合法,只能各处用到时各自防御性读取。</li><li><strong>难精确匹配</strong>:配方、谓词(predicate)、命令选择器要判断&quot;这把剑是不是附了锋利&quot;,得去 <code>tag</code> 里手动翻嵌套结构,匹配逻辑又臭又长,而且容易因为&quot;多了个无关键&quot;就匹配失败或成功。</li><li><strong>耦合</strong>:<code>display.Name</code>、<code>Enchantments</code>、<code>Damage</code> 全挤在同一个 Compound 里,语义边界靠约定俗成的键名维持。</li></ul><p>这套能用,Minecraft 也确实用了很多年。但它本质是&quot;把所有物品的所有可能字段塞进同一个自由表&quot;,越往后字段越多,越难管。</p><hr><h2 id="二、新世界-物品-种类-一组类型化组件" tabindex="-1">二、新世界:物品 = 种类 + 一组类型化组件 <a class="header-anchor" href="#二、新世界-物品-种类-一组类型化组件" aria-label="Permalink to &quot;二、新世界:物品 = 种类 + 一组类型化组件&quot;">​</a></h2><p>1.20.5 起,ItemStack 变成:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>物品种类(minecraft:diamond_sword)</span></span>
<span class="line"><span>  + 一组组件 components: 一个 “组件类型 → 值” 的映射</span></span>
<span class="line"><span>      minecraft:max_damage      → 1561</span></span>
<span class="line"><span>      minecraft:damage          → 12</span></span>
<span class="line"><span>      minecraft:enchantments    → {sharpness: 5}</span></span>
<span class="line"><span>      minecraft:custom_name     → &quot;断钢&quot;</span></span>
<span class="line"><span>      minecraft:lore            → [...]</span></span>
<span class="line"><span>      minecraft:attribute_modifiers → [...]</span></span></code></pre></div><p>关键变化不只是改了个名字,而是<strong>每个组件都是一个注册过的、强类型的东西</strong>(<code>minecraft:damage</code>、<code>minecraft:food</code>、<code>minecraft:container</code>、<code>minecraft:custom_name</code>……),它们登记在一个组件类型注册表里(呼应第 11 篇:一切类型都进注册表)。一个组件有明确的值类型、明确的序列化方式、明确的默认值。</p><h3 id="默认组件-实例只存差异" tabindex="-1">默认组件 + 实例只存差异 <a class="header-anchor" href="#默认组件-实例只存差异" aria-label="Permalink to &quot;默认组件 + 实例只存差异&quot;">​</a></h3><p>这是新模型最聪明的一点,和第 09 篇讲方块&quot;不存逐实例数据&quot;是同一种思路。</p><ul><li>每个<strong>物品种类</strong>自带一组<strong>默认组件</strong>(prototype)。比如所有钻石剑默认 <code>max_damage=1561</code>、<code>attack_damage</code>、<code>tool</code> 规则等。</li><li>一个<strong>具体物品实例</strong>,只存它<strong>相对默认值的差异</strong>:覆盖了哪些、删除了哪些。</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>钻石剑(种类)默认:  max_damage=1561, tool={...}, ...     ← 共享,不逐个存</span></span>
<span class="line"><span>你手里这把(实例):  + damage=12  + enchantments={sharpness:5}  + custom_name=&quot;断钢&quot;</span></span>
<span class="line"><span>                                                          ↑ 只存这三条覆盖</span></span></code></pre></div><p>所以一把没附魔没改名的普通钻石剑,实例侧几乎不存任何组件——和默认 prototype 一致。能共享的就不复制,这条主线在物品层又出现了一次。</p><h3 id="可以-删默认值-——一个反直觉点" tabindex="-1">可以&quot;删默认值&quot;——一个反直觉点 <a class="header-anchor" href="#可以-删默认值-——一个反直觉点" aria-label="Permalink to &quot;可以&quot;删默认值&quot;——一个反直觉点&quot;">​</a></h3><p>既然实例是&quot;对默认的覆盖&quot;,那就必然需要一个操作:<strong>移除某个本来默认存在的组件</strong>。命令里写成 <code>!minecraft:component</code>(带感叹号),意思是&quot;在这个物品上把这个默认组件去掉&quot;。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/give @s minecraft:diamond_sword[!minecraft:enchantment_glint_override]</span></span>
<span class="line"><span>                                  ↑ 去掉默认的某组件</span></span>
<span class="line"><span>/give @s minecraft:stick[minecraft:food={nutrition:4}]   ← 给棍子加上“能吃”</span></span></code></pre></div><p>第一次见 <code>!</code> 前缀的人都会愣一下:不是&quot;设为空&quot;,而是&quot;从默认集合里删掉这一项&quot;。这正是&quot;实例 = 对默认的 diff&quot;模型的直接体现——diff 既能加、能改,也能减。</p><hr><h2 id="三、为什么值得改-从-自由口袋-到-强类型契约" tabindex="-1">三、为什么值得改:从&quot;自由口袋&quot;到&quot;强类型契约&quot; <a class="header-anchor" href="#三、为什么值得改-从-自由口袋-到-强类型契约" aria-label="Permalink to &quot;三、为什么值得改:从&quot;自由口袋&quot;到&quot;强类型契约&quot;&quot;">​</a></h2><p>把前两节对起来看,改动的收益很清楚:</p><table tabindex="0"><thead><tr><th>维度</th><th>旧 <code>tag</code>(自由 NBT)</th><th>新 components(强类型)</th></tr></thead><tbody><tr><td>类型</td><td>弱类型,键随便加</td><td>每个组件注册过、有固定值类型</td></tr><tr><td>校验</td><td>用到才发现错</td><td>创建时即可校验合法性</td></tr><tr><td>匹配</td><td>手翻嵌套,易误判</td><td>按组件精确匹配,默认值参与合并</td></tr><tr><td>边界</td><td>全挤一个 Compound</td><td>每个组件语义独立、可单独读写</td></tr><tr><td>共享</td><td>每个物品自带全量 tag</td><td>默认来自种类,实例只存 diff</td></tr></tbody></table><p>对<strong>配方和谓词</strong>尤其关键。以前判断&quot;消耗一把附了锋利的剑&quot;,要写一段在 <code>tag.Enchantments</code> 里翻数组、还要担心其它无关键干扰的逻辑;现在直接声明&quot;需要 <code>minecraft:enchantments</code> 含 sharpness&quot;,由强类型组件系统去比对,默认值也按规则参与。匹配从&quot;字符串/结构层面的脆弱比对&quot;变成&quot;类型层面的明确契约&quot;。</p><p>命令侧的体感变化:旧的 <code>{tag}</code> 语法整体被 <code>[component=value]</code> 取代。这不是语法糖,而是底层模型换了之后命令必须跟着换——你操作的对象从&quot;一个 NBT 口袋&quot;变成了&quot;一组有名有姓的组件&quot;。</p><blockquote><p>注意边界:这次换的是<strong>物品</strong>的数据模型。方块实体(箱子内容、告示牌)、实体的存档,<strong>仍然是 NBT</strong>(第 08 篇那套)。组件化目前是物品这条线的事,别误以为整个游戏都不用 NBT 了。</p></blockquote><hr><h2 id="四、datafixerupper-旧结构怎么变成新结构" tabindex="-1">四、DataFixerUpper:旧结构怎么变成新结构 <a class="header-anchor" href="#四、datafixerupper-旧结构怎么变成新结构" aria-label="Permalink to &quot;四、DataFixerUpper:旧结构怎么变成新结构&quot;">​</a></h2><p>上面这种&quot;地基级&quot;的数据模型重构,会立刻引出一个尖锐的问题:<strong>那我 1.20.4 存的世界,里面全是 <code>tag</code> 格式的物品,1.20.5 怎么读?</strong> 更一般地:Minecraft 十几年改了无数次数据结构(方块 ID 扁平化、世界变高、实体拆分存储、物品组件化……),凭什么老存档还能打开?</p><p>答案是 <strong>DataFixerUpper(DFU)</strong>——一套专门做&quot;数据结构跨版本迁移&quot;的机制。</p><h3 id="dataversion-每份数据都带着-我是哪一版" tabindex="-1">DataVersion:每份数据都带着&quot;我是哪一版&quot; <a class="header-anchor" href="#dataversion-每份数据都带着-我是哪一版" aria-label="Permalink to &quot;DataVersion:每份数据都带着&quot;我是哪一版&quot;&quot;">​</a></h3><p>回顾第 02、08 篇:几乎每份存档数据(<code>level.dat</code>、每个 chunk、每个实体)都带一个 <strong>DataVersion</strong>(一个单调递增的整数)。它就是迁移的锚点——加载时,游戏先看这份数据的 DataVersion,和当前版本一比,就知道&quot;中间隔了哪些结构变更,要补哪些迁移&quot;。</p><h3 id="type-schema-按版本叠加的-fixer" tabindex="-1">type schema + 按版本叠加的 fixer <a class="header-anchor" href="#type-schema-按版本叠加的-fixer" aria-label="Permalink to &quot;type schema + 按版本叠加的 fixer&quot;">​</a></h3><p>DFU 的核心不是&quot;if 旧版 then 手改字段&quot;这种散装补丁,而是一套更结构化的东西:</p><ul><li><strong>type schema</strong>:为&quot;某个版本下,一个 chunk / 一个实体 / 一个物品的结构长什么样&quot;建立类型描述。</li><li><strong>fixer / rewrite rule</strong>:每个引入结构变更的版本,登记一组重写规则——把上一版 schema 的数据,改写成本版 schema 的数据。比如&quot;1.20.5 这一版:把 <code>tag</code> 里的字段按映射拆成对应的 components&quot;。</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DataVersion 升级链(示意):</span></span>
<span class="line"><span></span></span>
<span class="line"><span>旧存档 (v3700)</span></span>
<span class="line"><span>   │  应用 v3701 的 fixer:tag → components 拆解</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>   (v3701)</span></span>
<span class="line"><span>   │  应用 v3702 的 fixer:某组件改名 / 某字段挪位</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>   ...逐版本叠加...</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>当前版本结构 (vNNNN)  →  交给游戏正常加载</span></span></code></pre></div><p>关键点:迁移是<strong>逐版本累加</strong>的,不是&quot;从任意旧版直接跳到最新&quot;的一个大函数。每个版本只负责&quot;我相对上一版改了什么&quot;。任意旧版本的数据,沿着这条链一路重写上来,最后都变成当前版本认识的结构。<strong>这就是老世界能打开的全部秘密</strong>——不是游戏&quot;兼容&quot;旧格式,而是加载前先把旧格式<strong>重写成</strong>新格式。</p><h3 id="它和组件化是一回事的两面" tabindex="-1">它和组件化是一回事的两面 <a class="header-anchor" href="#它和组件化是一回事的两面" aria-label="Permalink to &quot;它和组件化是一回事的两面&quot;">​</a></h3><p>把第三、四节合起来看:</p><ul><li>组件化解决&quot;<strong>从现在起</strong>,物品该怎么存&quot;——强类型、可校验、存 diff。</li><li>DFU 解决&quot;<strong>过去存的</strong>,怎么变成现在这样&quot;——按 DataVersion 把 <code>tag</code> 重写成 components。</li></ul><p>没有 DFU,组件化这种重构就没法做——你不能为了改进数据模型就抛弃所有老存档。<strong>正是因为有 DFU 兜底迁移,Mojang 才敢一次次动地基。</strong> 这也是为什么这两件事值得放在同一篇里讲:它们是&quot;数据模型演进&quot;这件事的正向设计与向后兼容两面。</p><hr><h2 id="五、踩坑与反直觉" tabindex="-1">五、踩坑与反直觉 <a class="header-anchor" href="#五、踩坑与反直觉" aria-label="Permalink to &quot;五、踩坑与反直觉&quot;">​</a></h2><ul><li><strong><code>!</code> 不是清空,是删默认</strong>:<code>[!minecraft:xxx]</code> 是&quot;把这个默认组件从物品上摘掉&quot;,不是&quot;设成空值&quot;。这是 diff 模型的直接后果。</li><li><strong>匹配要考虑默认值</strong>:判断两个物品&quot;组件是否相同&quot;时,实例侧没写的组件会回落到种类默认值。所以&quot;看起来组件列表不一样&quot;的两个物品,合并默认后可能等价;反过来也成立。别只比实例侧的 diff。</li><li><strong>大版本首次加载特别慢</strong>:跨了很多版本的老世界第一次在新版本打开,DFU 要对<strong>每个 chunk、每个实体</strong>沿升级链逐版本重写,CPU 和时间开销显著。这不是卡死,是在做一次全量数据迁移;迁移并存盘后,之后加载就快了(DataVersion 已是新的,不再触发 fixer)。</li><li><strong>NBT 没有退场</strong>:再强调一次,组件化是物品这条线;方块实体、实体存档仍是 NBT。两套模型在当前版本是并存的。</li><li><strong>DFU 不是双向的</strong>:它只负责&quot;旧 → 新&quot;。新版本存的世界,旧版本客户端基本打不开——没有&quot;降级 fixer&quot;。</li></ul><hr><h2 id="六、串联" tabindex="-1">六、串联 <a class="header-anchor" href="#六、串联" aria-label="Permalink to &quot;六、串联&quot;">​</a></h2><p>把这一篇接回前面:</p><ul><li><strong>第 08 篇</strong>给了 NBT 的字节模型和 DataVersion 的概念,这一篇说明了 DataVersion 真正的用武之地——驱动 DFU 的升级链。</li><li><strong>第 11 篇</strong>讲注册表是&quot;一切类型的总账&quot;,组件类型同样登记在注册表里;组件化本质是把物品数据也纳入&quot;强类型、可注册、可数据驱动&quot;的世界观。</li><li>和<strong>第 09 篇</strong>方块&quot;不存逐实例数据&quot;对照:物品的&quot;默认组件 + 实例存 diff&quot;,是同一条主线在物品层的复现——<strong>能共享的就不复制</strong>。</li></ul><p>所以这一篇其实是整个系列那条暗线的一个集中体现:Minecraft 一直在把&quot;自由、弱类型、什么都能塞&quot;的数据,慢慢收紧成&quot;强类型、可校验、可迁移&quot;的结构;而每一次收紧地基,背后都得有 DataFixerUpper 这样的迁移机制兜底,旧世界才不会被丢下。</p>`,54)])])}const g=t(o,[["render",p]]);export{q as __pageData,g as default};
